CK_DLL_MFUN( grain_openFile )
{
    // get grain
    FileGrain* g_obj = ( FileGrain* )OBJ_MEMBER_INT( SELF, grain_data_offset );
    // get file
    Chuck_String* path = GET_NEXT_STRING( ARGS );

    if( g_obj ) g_obj->openFile( API->object->str( path ) );
}

CK_DLL_MFUN( grain_closeFile )
{
    // get grain
    FileGrain* g_obj = ( FileGrain* )OBJ_MEMBER_INT( SELF, grain_data_offset );
    
    if( g_obj ) g_obj->samp->closeFile();
}

CK_DLL_MFUN( grain_fileSize )
{
    // get grain
    FileGrain* g_obj = ( FileGrain* )OBJ_MEMBER_INT( SELF, grain_data_offset );

    if( g_obj ) RETURN->v_int = g_obj->samp->getFileSize();
    else RETURN->v_int = -1;
}